// =============================================
// UNIR DATOS DE AMBOS NODOS - FORMATO ESPECÍFICO
// =============================================

// 1. Obtener datos de Preparar_Input_AI (primer elemento del merge)
const datosPrepararInput = $input.all()[0]?.json || {};

// 2. Obtener datos de Consultar_estado_Odoo (segundo elemento del merge)
// La respuesta de Odoo viene como array: [{...}]
let datosOdoo = $input.all()[1]?.json;
if (Array.isArray(datosOdoo) && datosOdoo.length > 0) {
    datosOdoo = datosOdoo[0];
} else {
    datosOdoo = datosOdoo || {};
}

console.log("📥 DATOS DE ODOO (crudo):", JSON.stringify($input.all()[1]?.json, null, 2));
console.log("📥 DATOS DE ODOO (procesado):", JSON.stringify(datosOdoo, null, 2));

// 3. Extraer el estado_anterior - AHORA SE LLAMA "estado" en lugar de "debug_estado_nuevo"
const estado_anterior = datosOdoo.estado || null;
const modoOdoo = estado_anterior?.modo || datosOdoo.modo || null;
const pasoOdoo = estado_anterior?.paso || datosOdoo.paso || null;

// 4. Crear el resultado en el formato EXACTO solicitado
const resultadoFinal = {
    // Campos de Preparar_Input_AI
    text: datosPrepararInput.text || "0",
    session_id: datosPrepararInput.session_id || "",
    image_url: datosPrepararInput.image_url || "",
    platform: datosPrepararInput.platform || "whatsapp",
    account_id: datosPrepararInput.account_id || "",
    conversation_id: datosPrepararInput.conversation_id || "",

    // Campos de Odoo (estado_anterior completo)
    estado_anterior: estado_anterior,

    // Campos adicionales de Odoo (modo y paso al nivel raíz también)
    modo: modoOdoo,
    paso: pasoOdoo,

    // Datos paciente para fácil acceso
    datos_paciente: estado_anterior?.datos_paciente || {}
};

// 5. Si estado_anterior es null, crear estructura básica
if (!estado_anterior) {
    resultadoFinal.estado_anterior = {
        modo: datosOdoo.modo || null,
        paso: datosOdoo.paso || null,
        datos_paciente: {},
        timestamp: null
    };
}

console.log("✅ RESULTADO FINAL:");
console.log(JSON.stringify(resultadoFinal, null, 2));

return [{ json: resultadoFinal }];

// =============================================
// PROCESADOR SIMPLIFICADO DE RESULTADO DE BÚSQUEDA - CORREGIDO
// =============================================

try {
  // 1. OBTENER DATOS DE ENTRADA
  const datosEntrada = $json || {};

  console.log("=== PROCESADOR DE BÚSQUEDA - ENTRADA ===");
  console.log("Tipo de entrada:", typeof datosEntrada);
  console.log("Es array?:", Array.isArray(datosEntrada));
  console.log("Contenido entrada:", JSON.stringify(datosEntrada, null, 2));

  // Variables por defecto
  let estado_anterior = {
    modo: "AGENDANDO_CITA",
    paso: "SOLICITAR_TELEFONO",
    timestamp: new Date().toISOString(),
    datos_paciente: {}
  };

  let datos_paciente = {};
  let siguiente_paso = "SOLICITAR_TELEFONO";
  let respuesta = "";
  let modo = "AGENDANDO_CITA";
  let telefono_buscado = null;

  // 2. BUSCAR EL ARRAY DE RESULTADO EN LA ENTRADA
  let resultadoArray = null;

  if (Array.isArray(datosEntrada)) {
    resultadoArray = datosEntrada;
    console.log("✅ Entrada detectada como array directo");
  } else if (typeof datosEntrada === 'object') {
    for (const key in datosEntrada) {
      if (Array.isArray(datosEntrada[key])) {
        resultadoArray = datosEntrada[key];
        console.log(`✅ Array encontrado en propiedad: ${key}`);
        break;
      }
    }

    if (!resultadoArray && datosEntrada.existe !== undefined) {
      resultadoArray = [datosEntrada];
      console.log("✅ Objeto de paciente convertido a array");
    }
  }

  // 3. PROCESAR EL RESULTADO
  if (resultadoArray && resultadoArray.length > 0) {
    const resultado = resultadoArray[0];

    // Extraer el teléfono buscado de diferentes campos posibles
    telefono_buscado = resultado.telefono_buscado || resultado.telefono || null;

    if (resultado.existe === true) {
      console.log("✅ PACIENTE ENCONTRADO EN EL SISTEMA");

      // Cargar datos del paciente
      datos_paciente = {
        nombre: resultado.nombre_completo || null,
        cedula: resultado.cedula || null,
        telefono: telefono_buscado || resultado.telefono || null,
        fecha_nacimiento: resultado.fecha_nacimiento || null
      };

      const es_paciente_nuevo = (resultado.es_paciente_nuevo || "").toLowerCase();

      // Determinar el siguiente paso
      if (es_paciente_nuevo === "si") {
        datos_paciente.paciente_nuevo = "SI";
        siguiente_paso = "SOLICITAR_MEDIO_PAGO";

        respuesta = `✅ **TUS DATOS HAN SIDO CARGADOS AUTOMÁTICAMENTE**\n\n` +
          `🔍 Encontramos tu información en el sistema:\n\n` +
          `• Nombre: ${datos_paciente.nombre}\n` +
          `• Cédula: ${datos_paciente.cedula}\n` +
          `• Fecha de nacimiento: ${datos_paciente.fecha_nacimiento}\n` +
          `• Teléfono: ${datos_paciente.telefono || 'No cargado'}\n\n` +
          `🏥 Eres paciente nuevo\n\n` +
          `💳 Ahora necesito saber tu medio de pago:\n\nEscribe:\n• PARTICULAR - para pago directo\n• SEGURO - si tienes seguro médico`;

      } else if (es_paciente_nuevo === "no") {
        datos_paciente.paciente_nuevo = "NO";
        siguiente_paso = "SOLICITAR_MEDIO_PAGO";

        respuesta = `✅ **TUS DATOS HAN SIDO CARGADOS AUTOMÁTICAMENTE**\n\n` +
          `🔍 Encontramos tu información en el sistema:\n\n` +
          `• Nombre: ${datos_paciente.nombre}\n` +
          `• Cédula: ${datos_paciente.cedula}\n` +
          `• Fecha de nacimiento: ${datos_paciente.fecha_nacimiento}\n` +
          `• Teléfono: ${datos_paciente.telefono || 'No cargado'}\n\n` +
          `🏥 Eres paciente existente\n\n` +
          `💳 Ahora necesito saber tu medio de pago:\n\nEscribe:\n• PARTICULAR - para pago directo\n• SEGURO - si tienes seguro médico`;

      } else {
        siguiente_paso = "SOLICITAR_PACIENTE_NUEVO";

        respuesta = `✅ **TUS DATOS HAN SIDO CARGADOS AUTOMÁTICAMENTE**\n\n` +
          `🔍 Encontramos tu información en el sistema:\n\n` +
          `• Nombre: ${datos_paciente.nombre}\n` +
          `• Cédula: ${datos_paciente.cedula}\n` +
          `• Fecha de nacimiento: ${datos_paciente.fecha_nacimiento}\n` +
          `• Teléfono: ${datos_paciente.telefono || 'No cargado'}\n\n` +
          `🏥 ¿Es tu primera vez en UNISA? (Responde SI o NO)`;
      }

      // Llenar también el estado_anterior.datos_paciente
      estado_anterior.datos_paciente = { ...datos_paciente };

    } else {
      // PACIENTE NO ENCONTRADO
      console.log("❌ PACIENTE NO ENCONTRADO EN EL SISTEMA");

      // Usar el mensaje que viene en el resultado o uno por defecto
      respuesta = resultado.mensaje || `❌ No encontré datos registrados con el teléfono ${telefono_buscado || 'proporcionado'}.\n\n📋 Por favor, escribe tu cédula (solo números) para continuar con el registro:`;

      siguiente_paso = "SOLICITAR_NOMBRE";

      // Llenar datos_paciente solo con el teléfono buscado
      datos_paciente = {
        telefono: telefono_buscado
      };

      // estado_anterior.datos_paciente se queda vacío como solicitas
      estado_anterior.datos_paciente = {};
    }
  } else {
    // Sin resultado válido
    siguiente_paso = "SOLICITAR_TELEFONO";
    respuesta = `❌ No se pudo procesar la búsqueda.\n\n📞 Por favor, envía tu número de teléfono nuevamente en formato +58 seguido de 10 dígitos.\n\nEjemplo: +584141234567`;

    datos_paciente = {
      telefono: null
    };

    estado_anterior.datos_paciente = {};
  }

  // 4. CONSTRUIR SALIDA
  const salida = {
    respuesta: respuesta,
    estado_anterior: estado_anterior,
    modo: modo,
    paso: siguiente_paso,
    datos_paciente: datos_paciente
  };

  console.log("=== SALIDA FINAL ===");
  console.log("Salida generada:", JSON.stringify(salida, null, 2));

  return [salida];

} catch (error) {
  console.error("ERROR en procesador de búsqueda:", error);

  // En caso de error, devolver estructura básica
  const salida_error = {
    respuesta: "⚠️ Hubo un error al procesar la búsqueda.\n\n📞 Por favor, envía tu número de teléfono nuevamente en formato +58 seguido de 10 dígitos.\n\nEjemplo: +584141234567",
    estado_anterior: {
      modo: "AGENDANDO_CITA",
      paso: "SOLICITAR_TELEFONO",
      timestamp: new Date().toISOString(),
      datos_paciente: {}
    },
    modo: "AGENDANDO_CITA",
    paso: "SOLICITAR_TELEFONO",
    datos_paciente: {}
  };

  return [salida_error];
}

// =============================================
// COMBINADOR OPTIMIZADO CON ESTADO_ACTUAL - VERSIÓN CORREGIDA
// =============================================

try {
  // Obtener las dos entradas del Merge (siempre llegan en este orden)
  const entrada1 = $input.all()[0]?.json || {};  // Contexto de la conversación
  const entrada2 = $input.all()[1]?.json || {};  // Resultado del procesador de búsqueda

  console.log("=== COMBINADOR CON ESTADO_ACTUAL ===");
  console.log("Entrada 1 (contexto):", JSON.stringify(entrada1, null, 2));
  console.log("Entrada 2 (procesador):", JSON.stringify(entrada2, null, 2));

  // Función auxiliar para verificar si un valor está realmente vacío
  function estaVacio(valor) {
    if (valor === null || valor === undefined) return true;
    if (typeof valor === 'string') return valor.trim() === '';
    if (typeof valor === 'object' && !Array.isArray(valor)) {
      return Object.keys(valor).length === 0;
    }
    return false;
  }

  // 1. DETERMINAR MODO Y PASO (dar prioridad a la segunda entrada si existe)
  let modo, paso;

  if (!estaVacio(entrada2)) {
    // Usar modo y paso de la segunda entrada (prioridad)
    modo = entrada2.modo || "";
    paso = entrada2.paso || "";

    console.log("Usando modo y paso de entrada2:", { modo, paso });
  } else {
    // Si no hay segunda entrada, usar modo y paso de la primera entrada
    modo = entrada1.modo || "";
    paso = entrada1.paso || "";

    console.log("Usando modo y paso de entrada1:", { modo, paso });
  }

  // 2. DETERMINAR DATOS_PACIENTE (combinar ambos)
  let datos_paciente = {};

  // Primero tomar los datos_paciente de la primera entrada
  if (entrada1.datos_paciente && !estaVacio(entrada1.datos_paciente)) {
    datos_paciente = { ...entrada1.datos_paciente };
    console.log("Datos paciente iniciales de entrada1:", datos_paciente);
  }

  // Luego sobrescribir/agregar con los datos de la segunda entrada
  if (entrada2.datos_paciente && !estaVacio(entrada2.datos_paciente)) {
    datos_paciente = { ...datos_paciente, ...entrada2.datos_paciente };
    console.log("Datos paciente actualizados con entrada2:", datos_paciente);
  }

  // 3. CONSTRUIR ESTADO_ACTUAL
  const timestamp = new Date().toISOString();

  const estado_actual = {
    modo: modo,
    paso: paso,
    timestamp: timestamp,
    datos_paciente: datos_paciente
  };

  // 4. CONSTRUIR RESULTADO FINAL
  const resultado = {
    // Campos de contexto (siempre de la primera entrada)
    text: entrada1.text || "",
    session_id: entrada1.session_id || "",
    image_url: entrada1.image_url || "",
    platform: entrada1.platform || "whatsapp",
    account_id: entrada1.account_id || "",
    conversation_id: entrada1.conversation_id || "",

    // Estado actual
    estado_actual: estado_actual,

    // Campos redundantes para compatibilidad (se extraen del estado_actual)
    modo: estado_actual.modo,
    paso: estado_actual.paso,
    datos_paciente: estado_actual.datos_paciente
  };

  console.log("=== SALIDA FINAL ===");
  console.log("Resultado generado:", JSON.stringify(resultado, null, 2));

  return [resultado];

} catch (error) {
  console.error("ERROR en combinador:", error);

  // Estructura de error con estado_actual
  const timestamp = new Date().toISOString();
  const estado_actual_error = {
    modo: "",
    paso: "",
    timestamp: timestamp,
    datos_paciente: {}
  };

  return [{
    text: "",
    session_id: "",
    image_url: "",
    platform: "whatsapp",
    account_id: "1",
    conversation_id: "7",
    estado_actual: estado_actual_error,
    modo: estado_actual_error.modo,
    paso: estado_actual_error.paso,
    datos_paciente: estado_actual_error.datos_paciente
  }];
}
